import{_ as t,o as i,c as a,ag as s}from"./chunks/framework.ByAj6Cie.js";const g=JSON.parse('{"title":"Voltage Sags","description":"","frontmatter":{},"headers":[],"relativePath":"en/power-quality/voltage-sags.md","filePath":"en/power-quality/voltage-sags.md"}'),o={name:"en/power-quality/voltage-sags.md"};function r(n,e,l,c,p,d){return i(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="voltage-sags" tabindex="-1">Voltage Sags <a class="header-anchor" href="#voltage-sags" aria-label="Permalink to &quot;Voltage Sags&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Voltage sags are short duration reductions in voltage magnitude, typically lasting from a few milliseconds to a few seconds.</p><p>They are one of the most common power quality disturbances in industrial systems and can affect equipment operation even when the reduction is relatively small.</p><p>Voltage sags do not completely interrupt power but reduce it below normal levels.</p><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>Understanding voltage sags is important to:</p><ul><li>Prevent unexpected equipment shutdowns</li><li>Maintain continuity of industrial processes</li><li>Protect sensitive electronic devices</li><li>Improve system reliability</li></ul><p>Managing voltage sags reduces production losses and operational disruptions.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>A voltage sag occurs when there is a sudden increase in current demand or a fault in the system.</p><p>This causes a temporary drop in voltage due to system impedance.</p><p>Common causes include:</p><ul><li>Motor starting, especially large motors</li><li>Short circuits or faults in nearby systems</li><li>Energizing transformers or heavy loads</li><li>Utility disturbances affecting the supply</li></ul><p>The severity of a sag depends on:</p><ul><li>Depth of the voltage reduction</li><li>Duration of the event</li><li>Sensitivity of connected equipment</li></ul><p>Even short sags can cause control systems or drives to trip.</p><h2 id="applications" tabindex="-1">Applications <a class="header-anchor" href="#applications" aria-label="Permalink to &quot;Applications&quot;">​</a></h2><p>Voltage sag considerations are important in:</p><ul><li>Motor driven systems such as pumps and compressors</li><li>Automated production lines</li><li>PLC based control systems</li><li>Variable frequency drives and power electronics</li><li>Facilities with continuous processes</li></ul><p>They are critical in environments where even brief interruptions affect production.</p><h2 id="key-considerations" tabindex="-1">Key Considerations <a class="header-anchor" href="#key-considerations" aria-label="Permalink to &quot;Key Considerations&quot;">​</a></h2><ul><li><p><strong>Sag depth</strong><br> Greater voltage reduction increases the likelihood of equipment malfunction</p></li><li><p><strong>Duration</strong><br> Longer sags are more likely to cause trips or shutdowns</p></li><li><p><strong>Load sensitivity</strong><br> Electronic devices are more sensitive than resistive loads</p></li><li><p><strong>System strength</strong><br> Systems with lower impedance experience smaller voltage drops</p></li><li><p><strong>Starting methods</strong><br> Motor starting techniques can reduce sag impact</p></li><li><p><strong>Coordination with protection</strong><br> Protection settings must avoid unnecessary trips during temporary sags</p></li></ul><h2 id="practical-notes" tabindex="-1">Practical Notes <a class="header-anchor" href="#practical-notes" aria-label="Permalink to &quot;Practical Notes&quot;">​</a></h2><ul><li>Large motor starting is a common internal cause of voltage sags</li><li>Drives and control systems often trip before motors are affected</li><li>Soft starters and variable speed drives can reduce sag severity</li><li>Separating sensitive loads from heavy loads improves stability</li><li>Monitoring helps identify the source and frequency of sag events</li></ul>',25)])])}const h=t(o,[["render",r]]);export{g as __pageData,h as default};
